<body>

  <h1>⚡ Race Condition Demo</h1>
  <p class="subtitle">Rapidly click the buttons to trigger the race condition &mdash; watch the counts diverge!</p>

  <!-- ══════════════════════════════════════════
       INTERACTIVE PANELS
  ═══════════════════════════════════════════ -->
  <div class="panels">

    <!-- BUGGY PANEL -->
    <div class="panel panel-buggy">
      <span class="panel-label">🐛 Buggy Version</span>
      <h2>Async Counter (Race Bug)</h2>

