    <!-- FIXED PANEL -->
    <div class="panel panel-fixed">
      <span class="panel-label">✅ Fixed Version</span>
      <h2>Async Counter (Fixed)</h2>

      <div class="counter-wrap">
        <div class="counter-ring" id="fixed-display">0</div>
      </div>

      <div class="stats">
        <div class="stat-box">
          <div class="stat-label">Clicks</div>
          <div class="stat-value stat-expected" id="fixed-clicks">0</div>
        </div>
        <div class="stat-box">
