<span class="cm">// ❌ BUGGY — stale closure captures count before delay</span>
<span class="kw">function</span> <span class="fn">buggyIncrement</span>() {
  <span class="bad-line">  <span class="kw">const</span> captured = count;           <span class="cm">// read NOW (stale!)</span></span>
  <span class="kw">setTimeout</span>(() => {
    <span class="bad-line">    count = captured + <span class="str">1</span>;         <span class="cm">// write STALE value back</span></span>
    updateUI();
  }, <span class="str">300</span>);
}

<span class="cm">// ✅ FIXED — always increment the live variable</span>
<span class="kw">function</span> <span class="fn">fixedIncrement</span>() {
  <span class="good-line">  pendingCount++;                   <span class="cm">// track in-flight ops</span></span>
  <span class="kw">setTimeout</span>(() => {
    <span class="good-line">    count++;                        <span class="cm">// read+write atomically at callback time</span></span>
    <span class="good-line">    pendingCount--;                 <span class="cm">// op complete</span></span>
    updateUI();
  }, <span class="str">300</span>);
}
