<script>
  // ── Shared state ──────────────────────────────────────────────
  let buggyCount      = 0;
  let buggyExpected   = 0;
  let buggyPending    = 0;

  let fixedCount      = 0;
  let fixedExpected   = 0;
  let fixedPending    = 0;   // queue tracker (the fix)

  let totalClicks     = 0;

  // ── Timeline data ─────────────────────────────────────────────
  const TL_DURATION   = 6000;   // ms of history shown
  const tlOps         = [];     // { start, end, type:'buggy'|'fixed', clobber:bool }
  let   tlLastBuggyWrite = null;

  // ── Dot helpers ───────────────────────────────────────────────
  function updateDots(prefix, count, cls) {
    for (let i = 0; i < 8; i++) {
      const d = document.getElementById(`${prefix}${i}`);
      if (i < count) {
        d.classList.add('active', cls);
      } else {
        d.classList.remove('active', cls);
      }
    }
  }

  // ── Bump animation ────────────────────────────────────────────
  function bump(id) {
    const el = document.getElementById(id);
    el.classList.remove('bump');
    void el.offsetWidth;
    el.classList.add('bump');
    setTimeout(() => el.classList.remove('bump'), 150);
  }

  // ── Stats bar ─────────────────────────────────────────────────
  function updateStats() {
    const lost = Math.max(0, buggyExpected - buggyCount);
    document.getElementById('stat-lost').textContent    = lost;
    document.getElementById('stat-clicks').textContent  = totalClicks;
    document.getElementById('stat-correct').textContent = fixedCount;
  }

  // ── Buggy UI update ───────────────────────────────────────────
  function updateBuggyUI() {
    document.getElementById('buggy-count').textContent    = buggyCount;
    document.getElementById('buggy-expected').textContent = buggyExpected;
    const diff = buggyExpected - buggyCount;
    const disc = document.getElementById('buggy-disc');
    disc.textContent = diff > 0
      ? `⚠️ ${diff} update${diff>1?'s':''} lost to race condition!`
      : diff === 0 ? '✓ No discrepancy yet' : '';
    updateDots('bd', buggyPending, 'buggy-dot');
    updateStats();
  }

  // ── Fixed UI update ───────────────────────────────────────────
  function updateFixedUI() {
    document.getElementById('fixed-count').textContent    = fixedCount;
    document.getElementById('fixed-expected').textContent = fixedExpected;
    const diff = fixedExpected - fixedCount;
    const disc = document.getElementById('fixed-disc');
    disc.textContent = diff === 0
      ? '✅ Count is always accurate!'
      : `Processing ${fixedPending} pending…`;
    updateDots('fd', fixedPending, 'fixed-dot');
    updateStats();
  }

  // ── BUGGY increment ───────────────────────────────────────────
  function buggyIncrement() {
    buggyExpected++;
    totalClicks++;
    bump('buggy-count');

    // ★ The bug: capture count NOW before the async delay
    const capturedCount = buggyCount;
    buggyPending++;
    updateDots('bd', buggyPending, 'buggy-dot');

    const opStart = performance.now();
    const delay   = 200 + Math.random() * 200;   // 200–400 ms

    setTimeout(() => {
      // ★ Write back the stale captured value + 1
      const prevCount = buggyCount;
      buggyCount = capturedCount + 1;

      // detect clobber: if someone else already wrote a higher value
      const clobbered = prevCount > capturedCount + 1;
      if (clobbered) buggyCount = Math.max(prevCount, buggyCount);

      // record timeline op
      tlOps.push({
        start:   opStart,
        end:     performance.now(),
        type:    'buggy',
        clobber: prevCount !== capturedCount   // stale read detected
      });

      buggyPending--;
      bump('buggy-count');
      updateBuggyUI();
      drawTimeline();
    }, delay);

    updateBuggyUI();
  }

  // ── FIXED increment ───────────────────────────────────────────
  function fixedIncrement() {
    fixedExpected++;
    totalClicks++;
    bump('fixed-count');

    // ★ The fix: just track that an op is in flight
    fixedPending++;
    updateDots('fd', fixedPending, 'fixed-dot');

    const opStart = performance.now();
    const delay   = 200 + Math.random() * 200;

    setTimeout(() => {
      // ★ Read+increment at callback time — always fresh
      fixedCount++;
      fixedPending--;

      tlOps.push({
        start:   opStart,
        end:     performance.now(),
        type:    'fixed',
        clobber: false
      });

      bump('fixed-count');
      updateFixedUI();
      drawTimeline();
    }, delay);

    updateFixedUI();
  }

  // ── Rapid-fire helpers ────────────────────────────────────────
  function buggyRapid() {
    for (let i = 0; i < 10; i++) setTimeout(buggyIncrement, i * 30);
  }
  function fixedRapid() {
    for (let i = 0; i < 10; i++) setTimeout(fixedIncrement, i * 30);
  }

  // ── Reset ─────────────────────────────────────────────────────
  function resetBuggy() {
    buggyCount = buggyExpected = buggyPending = 0;
    updateBuggyUI();
  }
  function resetFixed() {
    fixedCount = fixedExpected = fixedPending = 0;
    updateFixedUI();
  }

  // ── Timeline canvas ───────────────────────────────────────────
  const canvas = document.getElementById('timeline-canvas');
  const ctx    = canvas.getContext('2d');

  function resizeCanvas() {
    canvas.width  = canvas.offsetWidth  * window.devicePixelRatio;
    canvas.height = canvas.offsetHeight * window.devicePixelRatio;
    ctx.scale(window.devicePixelRatio, window.devicePixelRatio);
    drawTimeline();
  }

  function drawTimeline() {
    const W = canvas.offsetWidth;
    const H = canvas.offsetHeight;
    ctx.clearRect(0, 0, W, H);

    const now     = performance.now();
    const tStart  = now - TL_DURATION;

    // background grid
    ctx.strokeStyle = '#1e1e3a';
    ctx.lineWidth   = 1;
    for (let x = 0; x < W; x += W / 12) {
      ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, H); ctx.stroke();
    }

    // lane labels
    const LANE_BUGGY = H * 0.25;
    const LANE_FIXED = H * 0.65;
    const LANE_H     = H * 0.22;

    ctx.font      = '11px Segoe UI';
    ctx.fillStyle = '#ff6b6b';
    ctx.fillText('Buggy ops', 6, LANE_BUGGY - LANE_H / 2 - 4);
    ctx.fillStyle = '#44ff88';
    ctx.fillText('Fixed ops', 6, LANE_FIXED - LANE_H / 2 - 4);

    // prune old ops
    const visible = tlOps.filter(op => op.end >= tStart);

    visible.forEach(op => {
      const x1 = Math.max(0, ((op.start - tStart) / TL_DURATION) * W);
      const x2 = Math.min(W, ((op.end   - tStart) / TL_DURATION) * W);
      const laneY = op.type === 'buggy' ? LANE_BUGGY : LANE_FIXED;

      // bar
      const grad = ctx.createLinearGradient(x1, 0, x2, 0);
      if (op.type === 'buggy') {
        grad.addColorStop(0, op.clobber ? '#ff000088' : '#ff444488');
        grad.addColorStop(1, op.clobber ? '#ff0000cc' : '#ff4444cc');
      } else {
        grad.addColorStop(0, '#44ff8888');
        grad.addColorStop(1, '#44ff88cc');
      }
      ctx.fillStyle = grad;
      ctx.beginPath();
      ctx.roundRect(x1, laneY - LANE_H / 2, Math.max(x2 - x1, 4), LANE_H, 4);
      ctx.fill();

      // clobber marker
      if (op.clobber) {
        ctx.fillStyle = '#a78bfa';
        ctx.beginPath();
        ctx.arc(x2, laneY, 5, 0, Math.PI * 2);
        ctx.fill();
      }

      // end tick
      ctx.strokeStyle = op.type === 'buggy' ? '#ff6b6b' : '#44ff88';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(x2, laneY - LANE_H / 2);
      ctx.lineTo(x2, laneY + LANE_H / 2);
      ctx.stroke();
    });

    // "now" line
    ctx.strokeStyle = '#ffffff33';
    ctx.lineWidth   = 1;
    ctx.setLineDash([4, 4]);
    ctx.beginPath();
    ctx.moveTo(W - 1, 0);
    ctx.lineTo(W - 1, H);
    ctx.stroke();
    ctx.setLineDash([]);
  }

  // redraw timeline continuously
  function tlLoop() {
    drawTimeline();
    requestAnimationFrame(tlLoop);
  }

  window.addEventListener('resize', resizeCanvas);
  resizeCanvas();
  tlLoop();

  // initial UI
  updateBuggyUI();
  updateFixedUI();
</script>
</body>
</html>
```

## What's Inside

### Two Side-by-Side Panels
| Panel | Behaviour |
|---|---|
| 🐛 **Buggy** | Captures `count` *before* the async delay — concurrent clicks all read the same stale value and clobber each other |
| ✅ **Fixed** | Increments `count` *inside* the callback (always the latest value) and tracks in-flight ops with a `pendingCount` guard |

### Key Features
- **Rapid ×10 button** — fires 10 overlapping async operations in quick succession so the race condition is immediately visible
- **Live discrepancy counter** — shows exactly how many updates were silently lost
- **Pending-ops dot indicators** — 8 dots per panel light up as operations are in flight
- **Live timeline canvas** — scrolling bar chart shows each async op as a coloured bar; purple dots mark clobber events where a stale write was detected
- **Stats bar** — running totals of lost updates, total clicks, and correct count
- **Colour-coded code block** — highlights the exact buggy line vs the fixed line with inline comments

