    </div>

    <div class="drift good" id="fixed-drift">Drift: 0</div>

    <button class="btn" id="fixed-btn" onmousedown="startRapid('fixed')" onmouseup="stopRapid('fixed')" ontouchstart="startRapid('fixed')" ontouchend="stopRapid('fixed')">
      ➕ Increment (hold!)
