<!-- ─────────────────────────── SCRIPT ─────────────────────────── -->
<script>
  // ── Shared state ──────────────────────────────────────────────
  let buggyCount    = 0;
  let buggyExpected = 0;

  let fixedCount    = 0;
  let fixedExpected = 0;

  // ── Rapid-click helpers (hold the button) ─────────────────────
  let rapidTimers = { buggy: null, fixed: null };

  function startRapid(which) {
    // Fire one immediately, then repeat every 80 ms while held
    fireIncrement(which);
    rapidTimers[which] = setInterval(() => fireIncrement(which), 80);
  }

  function stopRapid(which) {
    clearInterval(rapidTimers[which]);
    rapidTimers[which] = null;
  }

  function fireIncrement(which) {
    if (which === 'buggy') buggyIncrement();
    else                   fixedIncrement();
  }

  // ── Pop animation ─────────────────────────────────────────────
  function pop(id) {
    const el = document.getElementById(id);
    el.classList.remove('pop');
    void el.offsetWidth; // reflow
    el.classList.add('pop');
    setTimeout(() => el.classList.remove('pop'), 120);
  }

  // ── Log helpers ───────────────────────────────────────────────
  function log(boxId, msg, cls) {
    const box   = document.getElementById(boxId);
    const entry = document.createElement('div');
    entry.className = 'log-entry ' + (cls || '');
    entry.textContent = msg;
    box.appendChild(entry);
    box.scrollTop = box.scrollHeight;
    // Keep log from growing forever
    while (box.children.length > 60) box.removeChild(box.firstChild);
  }

  // ── Update drift badge ────────────────────────────────────────
  function updateDrift(which, actual, expected) {
    const drift = expected - actual;
    const el    = document.getElementById(which + '-drift');
    el.textContent = drift === 0
      ? 'Drift: 0 ✓'
      : `Drift: −${drift} ⚠️ (lost ${drift} update${drift !== 1 ? 's' : ''})`;
    el.className = 'drift ' + (drift === 0 ? 'good' : 'bad');
  }

  // ══════════════════════════════════════════════════════════════
  //  BUGGY VERSION
  //  Problem: reads a snapshot of buggyCount BEFORE the async
  //  delay, then writes snap+1 AFTER the delay. Rapid clicks all
  //  capture the same stale snapshot → multiple writes produce
  //  the same value → updates are silently lost.
  // ══════════════════════════════════════════════════════════════
  function buggyIncrement() {
    buggyExpected++;
    document.getElementById('buggy-expected').textContent = buggyExpected;

    // 🐛 BUG: capture a snapshot of the current count right now
    const snap = buggyCount;

    log('buggy-log',
      `Click #${buggyExpected}: read snap=${snap}`,
      '');

    // Simulate async work (e.g. network request) with random delay
    const delay = 50 + Math.random() * 150;

    setTimeout(() => {
      // 🐛 BUG: write back snap+1 — but snap may now be stale!
      buggyCount = snap + 1;

      document.getElementById('buggy-display').textContent = buggyCount;
      pop('buggy-display');

      const drift = buggyExpected - buggyCount;
      log('buggy-log',
        `  → wrote ${snap}+1=${buggyCount}` +
        (drift > 0 ? ` ⚠️ (lost ${drift})` : ' ✓'),
        drift > 0 ? 'log-race' : 'log-ok');

      updateDrift('buggy', buggyCount, buggyExpected);
    }, delay);
  }

  // ══════════════════════════════════════════════════════════════
  //  FIXED VERSION
  //  Solution: increment the shared counter SYNCHRONOUSLY in the
  //  click handler (before any async gap). The async callback
  //  only updates the UI — it never touches the counter value.
  //  JS's single-threaded model guarantees the sync increment is
  //  atomic; no two clicks can interleave during it.
  // ══════════════════════════════════════════════════════════════
  function fixedIncrement() {
    fixedExpected++;
    document.getElementById('fixed-expected').textContent = fixedExpected;

    // ✅ FIX: increment synchronously — no stale snapshot possible
    fixedCount++;
    const committed = fixedCount;   // capture the value WE incremented to

    log('fixed-log',
      `Click #${fixedExpected}: committed count=${committed}`,
      'log-ok');

    // Async work happens AFTER the increment is already locked in
    const delay = 50 + Math.random() * 150;

    setTimeout(() => {
      // ✅ Safe: we only display the value we already committed above
      document.getElementById('fixed-display').textContent = committed;
      pop('fixed-display');

      // Note: if multiple async callbacks resolve out of order the
      // display could momentarily show an older value, but the
      // counter itself is always correct.  For a real app you'd
      // use the latest committed value or a queue.
      log('fixed-log',
        `  → displayed ${committed} ✓`,
        'log-ok');

      updateDrift('fixed', fixedCount, fixedExpected);
    }, delay);
  }

  // ── Resets ────────────────────────────────────────────────────
  function resetBuggy() {
    buggyCount    = 0;
    buggyExpected = 0;
    document.getElementById('buggy-display').textContent  = '0';
    document.getElementById('buggy-expected').textContent = '0';
    document.getElementById('buggy-drift').textContent    = 'Drift: 0';
    document.getElementById('buggy-drift').className      = 'drift bad';
    document.getElementById('buggy-log').innerHTML        = '';
  }

  function resetFixed() {
    fixedCount    = 0;
    fixedExpected = 0;
    document.getElementById('fixed-display').textContent  = '0';
