<script>
  // ─────────────────────────────────────────────
  //  SHARED STATE
  // ─────────────────────────────────────────────
  let buggyCount    = 0;
  let buggyExpected = 0;

  let fixedCount    = 0;
  let fixedExpected = 0;

  // ─────────────────────────────────────────────
  //  HELPERS
  // ─────────────────────────────────────────────
  function bumpAnimation(id) {
    const el = document.getElementById(id);
    el.classList.remove('bump');
    // Force reflow so the class removal registers before re-adding
    void el.offsetWidth;
    el.classList.add('bump');
    setTimeout(() => el.classList.remove('bump'), 120);
  }

  function addLog(logId, text, type) {
    const log = document.getElementById(logId);
    const entry = document.createElement('div');
    entry.className = 'log-entry ' + type;
    const ts = new Date().toLocaleTimeString('en', { hour12: false,
      hour: '2-digit', minute: '2-digit', second: '2-digit' });
    entry.textContent = `[${ts}] ${text}`;
    log.prepend(entry);
    // Keep log from growing forever
    while (log.children.length > 40) log.removeChild(log.lastChild);
  }

  function updateBuggyUI() {
    document.getElementById('buggy-count').textContent    = buggyCount;
    document.getElementById('buggy-expected').textContent = buggyExpected;
    const lost = buggyExpected - buggyCount;
    document.getElementById('buggy-lost').textContent     = lost > 0 ? lost : 0;
    bumpAnimation('buggy-count');
  }

  function updateFixedUI() {
    document.getElementById('fixed-count').textContent    = fixedCount;
    document.getElementById('fixed-expected').textContent = fixedExpected;
    const lost = fixedExpected - fixedCount;
    document.getElementById('fixed-lost').textContent     = lost > 0 ? lost : 0;
    bumpAnimation('fixed-count');
  }

  // ─────────────────────────────────────────────
  //  BUGGY VERSION
  //  Problem: captures `buggyCount` in `val` at
  //  click time. By the time the callback fires,
  //  `val` is stale if other clicks ran first.
  // ─────────────────────────────────────────────
  function buggyIncrement() {
    buggyExpected++;

    // ⚠️  Stale closure — `val` is a snapshot, NOT a live reference
    const val = buggyCount;
    const clickNum = buggyExpected;

    addLog('buggy-log',
      `Click #${clickNum}: READ count=${val}`, 'read');

    setTimeout(() => {
      const newVal = val + 1;          // based on STALE snapshot
      buggyCount = newVal;             // write back

      const lost = clickNum - newVal;
      if (lost > 0) {
        addLog('buggy-log',
          `Click #${clickNum}: WRITE count=${newVal} ← LOST ${lost} update(s)!`, 'lost');
      } else {
        addLog('buggy-log',
          `Click #${clickNum}: WRITE count=${newVal}`, 'write');
      }
      updateBuggyUI();
    }, 80);   // short delay to make overlaps likely on rapid clicks
  }

  // ─────────────────────────────────────────────
  //  FIXED VERSION
  //  Solution: read `fixedCount` INSIDE the
  //  callback, right before writing. No stale
  //  snapshot is ever taken.
  // ─────────────────────────────────────────────
  function fixedIncrement() {
    fixedExpected++;
    const clickNum = fixedExpected;

    // No snapshot of fixedCount here — we'll read it fresh inside the callback
    addLog('fixed-log',
      `Click #${clickNum}: queued (will read fresh)`, 'read');

    setTimeout(() => {
      // ✅  Read the CURRENT value at execution time, not at schedule time
      const current = fixedCount;
      fixedCount = current + 1;

      addLog('fixed-log',
        `Click #${clickNum}: READ ${current} → WRITE ${fixedCount} ✓`, 'ok');
      updateFixedUI();
    }, 80);
  }

  // ─────────────────────────────────────────────
  //  RESETS
  // ─────────────────────────────────────────────
  function resetBuggy() {
    buggyCount = 0;
    buggyExpected = 0;
    document.getElementById('buggy-log').innerHTML = '';
    updateBuggyUI();
  }

  function resetFixed() {
    fixedCount = 0;
    fixedExpected = 0;
    document.getElementById('fixed-log').innerHTML = '';
    updateFixedUI();
  }
</script>
</body>
</html>
