<h1>⚡ Race Condition Demo</h1>
<p class="subtitle">Rapidly click <strong>+1</strong> on both widgets and watch what happens</p>

<!-- ═══════════════════════════════════════════
     WIDGETS
════════════════════════════════════════════ -->
<div class="columns">

  <!-- ── BUGGY WIDGET ── -->
  <div class="widget-card buggy">
    <span class="badge">⚠ Buggy</span>
    <div class="card-title">Race Condition Counter</div>

    <div class="count-display" id="buggy-display">0</div>

    <div class="pending-info" id="buggy-pending">idle</div>

    <div class="btn-row">
      <button class="btn-inc"   onclick="buggyIncrement()">+1</button>
      <button class="btn-dec"   onclick="buggyDecrement()">−1</button>
      <button class="btn-reset" onclick="buggyReset()">Reset</button>
    </div>

    <div class="log-box" id="buggy-log"></div>
  </div>

  <!-- ── FIXED WIDGET ── -->
  <div class="widget-card fixed">
    <span class="badge">✓ Fixed</span>
    <div class="card-title">Safe Async Counter</div>

    <div class="count-display" id="fixed-display">0</div>

    <div class="pending-info" id="fixed-pending">idle</div>

    <div class="btn-row">
      <button class="btn-inc"   onclick="fixedIncrement()">+1</button>
      <button class="btn-dec"   onclick="fixedDecrement()">−1</button>
      <button class="btn-reset" onclick="fixedReset()">Reset</button>
    </div>

    <div class="log-box" id="fixed-log"></div>
  </div>

