════════════════════════════════════════════ -->
<script>
/* ─────────────────────────────────────────────
   BUGGY COUNTER
   Race condition: each async callback reads the
   shared variable at dispatch time, so rapid
   clicks all see the same stale value.
───────────────────────────────────────────── */
let buggyCount   = 0;
let buggyPendingOps = 0;          // just for the UI label

const ASYNC_DELAY = 150;          // ms — long enough to overlap on rapid clicks

function buggyLog(msg, type = '') {
  const box  = document.getElementById('buggy-log');
  const line = document.createElement('div');
  line.className = 'log-entry' + (type ? ' log-' + type : '');
  line.textContent = msg;
  box.appendChild(line);
  box.scrollTop = box.scrollHeight;
}

function buggyUpdatePendingLabel() {
  const el = document.getElementById('buggy-pending');
  if (buggyPendingOps > 0) {
    el.textContent = `${buggyPendingOps} async op(s) in flight…`;
    el.classList.add('active');
  } else {
    el.textContent = 'idle';
    el.classList.remove('active');
  }
}

function buggyApplyDelta(delta, capturedCount) {
  // ⚠️ BUG: we read buggyCount at dispatch time (capturedCount),
  //         not at resolution time — so concurrent calls all
  //         compute from the same stale base value.
  const newValue = capturedCount + delta;
  buggyLog(
    `resolve: read=${capturedCount} + delta=${delta > 0 ? '+' + delta : delta} → write=${newValue}` +
    (newValue !== buggyCount + delta ? ' ⚠ CONFLICT!' : ''),
    newValue !== buggyCount + delta ? 'warn' : 'ok'
  );
  buggyCount = newValue;
  buggyPendingOps--;
  buggyUpdatePendingLabel();
  buggyRefreshDisplay();
}

function buggySchedule(delta) {
  const capturedCount = buggyCount;   // ← stale read happens HERE (synchronously)
  buggyPendingOps++;
  buggyUpdatePendingLabel();
  buggyLog(`dispatch: captured count=${capturedCount}, delta=${delta > 0 ? '+' + delta : delta}`, 'info');
  setTimeout(() => buggyApplyDelta(delta, capturedCount), ASYNC_DELAY);
}

function buggyRefreshDisplay() {
  const el = document.getElementById('buggy-display');
  el.textContent = buggyCount;
  el.classList.remove('bump');
  void el.offsetWidth;
  el.classList.add('bump');
  setTimeout(() => el.classList.remove('bump'), 150);
}

function buggyIncrement() { buggySchedule(+1); }
function buggyDecrement() { buggySchedule(-1); }
function buggyReset() {
  buggyCount = 0;
  buggyPendingOps = 0;
  buggyRefreshDisplay();
  buggyUpdatePendingLabel();
  document.getElementById('buggy-log').innerHTML = '';
  buggyLog('reset', 'info');
}


/* ─────────────────────────────────────────────
   FIXED COUNTER
   Solution: accumulate deltas synchronously into
   a pending queue; a single coalesced async
   callback drains the whole queue atomically.
───────────────────────────────────────────── */
let fixedCount   = 0;
let fixedPending = 0;             // accumulated delta — written synchronously
let fixedTimerActive = false;     // guard: only one timer in-flight at a time

function fixedLog(msg, type = '') {
  const box  = document.getElementById('fixed-log');
  const line = document.createElement('div');
  line.className = 'log-entry' + (type ? ' log-' + type : '');
  line.textContent = msg;
  box.appendChild(line);
  box.scrollTop = box.scrollHeight;
}

function fixedUpdatePendingLabel() {
  const el = document.getElementById('fixed-pending');
  if (fixedPending !== 0 || fixedTimerActive) {
    el.textContent = `queued delta: ${fixedPending > 0 ? '+' : ''}${fixedPending}`;
    el.classList.add('active');
  } else {
    el.textContent = 'idle';
    el.classList.remove('active');
  }
}

function fixedDrainQueue() {
  // ✅ FIX: read fixedPending at resolution time — it contains ALL
  //         accumulated deltas from every click that fired since
  //         the timer was scheduled.
  const delta = fixedPending;
  fixedPending = 0;
  fixedTimerActive = false;

  fixedCount += delta;
  fixedLog(`resolve: applied queued delta=${delta > 0 ? '+' + delta : delta} → count=${fixedCount}`, 'ok');
  fixedUpdatePendingLabel();
  fixedRefreshDisplay();
}

function fixedSchedule(delta) {
  // Accumulate delta synchronously — this is always safe
  fixedPending += delta;
  fixedLog(`queue:   pending=${fixedPending > 0 ? '+' : ''}${fixedPending}`, 'info');
  fixedUpdatePendingLabel();

  // Only start a new timer if one isn't already running
  if (!fixedTimerActive) {
    fixedTimerActive = true;
    setTimeout(fixedDrainQueue, ASYNC_DELAY);
  }
}

function fixedRefreshDisplay() {
  const el = document.getElementById('fixed-display');
  el.textContent = fixedCount;
  el.classList.remove('bump');
  void el.offsetWidth;
  el.classList.add('bump');
  setTimeout(() => el.classList.remove('bump'), 150);
}

function fixedIncrement() { fixedSchedule(+1); }
function fixedDecrement() { fixedSchedule(-1); }
function fixedReset() {
  fixedCount = 0;
  fixedPending = 0;
  fixedTimerActive = false;
  fixedRefreshDisplay();
  fixedUpdatePendingLabel();
  document.getElementById('fixed-log').innerHTML = '';
  fixedLog('reset', 'info');
}
</script>
</body>
