<!-- ═══════════════════════════ SCRIPT ═══════════════════════════ -->
<script>
  /* ─── Buggy state ─── */
  let buggyCount    = 0;
  let buggyExpected = 0;
  let buggyPendingN = 0;

  /* ─── Fixed state ─── */
  let fixedCount    = 0;
  let fixedExpected = 0;
  let fixedPendingN = 0;

  const DELAY = 200; // ms — long enough to overlap on rapid clicks

  /* ════════════════════════════
     Shared helpers
  ════════════════════════════ */
  function addLog(logId, msg, cls) {
    const box   = document.getElementById(logId);
    const entry = document.createElement('div');
    entry.className = 'log-entry ' + cls;
    const ts = new Date().toISOString().slice(11, 23);
    entry.textContent = `[${ts}] ${msg}`;
    box.appendChild(entry);
    box.scrollTop = box.scrollHeight;
    // keep log short
    while (box.children.length > 60) box.removeChild(box.firstChild);
  }

  function flashDisplay(id) {
    const el = document.getElementById(id);
    el.classList.add('flash');
    setTimeout(() => el.classList.remove('flash'), 300);
  }

  function bumpValue(id) {
    const el = document.getElementById(id);
    el.classList.add('bump');
    setTimeout(() => el.classList.remove('bump'), 120);
  }

  function updatePending(side, n) {
    const dotEl     = document.getElementById(side + 'Dot');
    const pendingEl = document.getElementById(side + 'Pending');
    if (n > 0) {
      dotEl.classList.add('active');
      pendingEl.textContent = `${n} async operation${n > 1 ? 's' : ''} in flight…`;
    } else {
      dotEl.classList.remove('active');
      pendingEl.textContent = 'No pending async operations';
    }
  }

  function updateDrift(side, actual, expected) {
    const driftEl = document.getElementById(side + 'Drift');
    const diff    = expected - actual;
    if (diff === 0) {
      driftEl.className = 'drift ok';
      driftEl.textContent = '✓ No drift — count is accurate';
    } else {
      driftEl.className = 'drift warn';
      driftEl.textContent = `⚠ Drift: expected ${expected}, got ${actual} (lost ${diff} update${diff !== 1 ? 's' : ''})`;
    }
  }

  /* ════════════════════════════
     BUGGY implementation
     Captures value in closure → stale write
  ════════════════════════════ */
  function buggyIncrement() {
    buggyExpected++;
    document.getElementById('buggyExpected').textContent = buggyExpected;

    // ⚠ THE BUG: snapshot count right now
    const capturedAtClickTime = buggyCount;
    buggyPendingN++;
    updatePending('buggy', buggyPendingN);
    addLog('buggyLog',
      `Click → captured count=${capturedAtClickTime}, waiting ${DELAY}ms…`,
      'warn');

    setTimeout(() => {
      // ⚠ Uses the stale snapshot, ignoring any updates that happened during the wait
      const oldVal  = buggyCount;
      buggyCount    = capturedAtClickTime + 1;

      buggyPendingN--;
      updatePending('buggy', buggyPendingN);

      document.getElementById('buggyCount').textContent = buggyCount;
      bumpValue('buggyCount');
      flashDisplay('buggyDisplay');
      updateDrift('buggy', buggyCount, buggyExpected);

      if (capturedAtClickTime !== oldVal) {
        addLog('buggyLog',
          `RACE! Wrote ${capturedAtClickTime}+1=${buggyCount} but live was ${oldVal} → lost update!`,
          'race');
      } else {
        addLog('buggyLog',
          `Resolved → count set to ${buggyCount}`,
          'info');
      }
    }, DELAY);
  }

  function spamBuggy() {
    addLog('buggyLog', '── Spam: 10 rapid clicks ──', 'info');
    for (let i = 0; i < 10; i++) {
      setTimeout(() => buggyIncrement(), i * 20); // 20 ms apart, well within DELAY
    }
  }

  function resetBuggy() {
    buggyCount    = 0;
    buggyExpected = 0;
    buggyPendingN = 0;
    document.getElementById('buggyCount').textContent    = 0;
    document.getElementById('buggyExpected').textContent = 0;
    updatePending('buggy', 0);
    updateDrift('buggy', 0, 0);
    document.getElementById('buggyDrift').textContent = '—';
    document.getElementById('buggyDrift').className   = 'drift';
    addLog('buggyLog', '── Reset ──', 'info');
  }

  /* ════════════════════════════
     FIXED implementation
     Reads live count at write-time → always correct
  ════════════════════════════ */
  function fixedIncrement() {
    fixedExpected++;
    document.getElementById('fixedExpected').textContent = fixedExpected;

    fixedPendingN++;
    updatePending('fixed', fixedPendingN);
    addLog('fixedLog',
      `Click → no capture, queuing increment, waiting ${DELAY}ms…`,
      'info');

    setTimeout(() => {
      // ✅ THE FIX: read the live value right now, at write-time
      fixedCount = fixedCount + 1;

      fixedPendingN--;
      updatePending('fixed', fixedPendingN);

      document.getElementById('fixedCount').textContent = fixedCount;
      bumpValue('fixedCount');
      flashDisplay('fixedDisplay');
      updateDrift('fixed', fixedCount, fixedExpected);

      addLog('fixedLog',
        `Resolved → read live count, wrote ${fixedCount}`,
        'ok');
    }, DELAY);
  }

  function spamFixed() {
    addLog('fixedLog', '── Spam: 10 rapid clicks ──', 'info');
    for (let i = 0; i < 10; i++) {
      setTimeout(() => fixedIncrement(), i * 20);
    }
  }

  function resetFixed() {
    fixedCount    = 0;
    fixedExpected = 0;
    fixedPendingN = 0;
    document.getElementById('fixedCount').textContent    = 0;
    document.getElementById('fixedExpected').textContent = 0;
    updatePending('fixed', 0);
    updateDrift('fixed', 0, 0);
    document.getElementById('fixedDrift').textContent = '—';
    document.getElementById('fixedDrift').className   = 'drift';
    addLog('fixedLog', '── Reset ──', 'info');
  }
</script>
</body>
</html>
```

## How to use it

1. **Save** the file as `race-condition-demo.html` and open it in any browser.
2. **Click "💥 Spam ×10"** on the buggy side — watch the count land well below 10 and the red drift warning appear.
3. **Click "💥 Spam ×10"** on the fixed side — it always lands exactly at 10 with no drift.

---

## What the demo teaches

| Concept | Buggy | Fixed |
|---|---|---|
| **When is `count` read?** | At click-time (captured in closure) | At write-time (inside the callback) |
| **What gets written?** | `stale_snapshot + 1` | `current_live_count + 1` |
| **Overlapping timers** | All read the same snapshot → overwrite each other | Each reads the value left by the previous one |
| **10 rapid clicks result** | Typically 1–3 | Always exactly 10 |

The **root cause** is the classic read-modify-write hazard: when multiple async operations each take a snapshot of shared state, do work, and then write back, the later writers silently discard every update that happened between their read and their write. The fix is simply to defer the read until the moment of the write, so there is never a stale snapshot to overwrite with.

