<span class="cm">// ✅ FIXED: serialized operation queue</span>
<span class="kw">const</span> queue = [];
<span class="kw">let</span> processing = <span class="kw">false</span>;

<span class="kw">function</span> <span class="fn">increment</span>() {
<span class="hlg">  queue.<span class="fn">push</span>(() => count + <span class="num">1</span>); <span class="cm">// enqueue</span></span>
<span class="hlg">  <span class="fn">processQueue</span>();</span>
}

<span class="kw">async function</span> <span class="fn">processQueue</span>() {
  <span class="kw">if</span> (processing) <span class="kw">return</span>; <span class="cm">// guard</span>
  processing = <span class="kw">true</span>;
  <span class="kw">while</span> (queue.length) {
<span class="hlg">    count = <span class="kw">await</span> queue.<span class="fn">shift</span>()();</span>
    render(count); <span class="cm">// always correct</span>
  }
  processing = <span class="kw">false</span>;
}
