<script>
  // ─────────────────────────────────────────────
  // BUGGY COUNTER STATE
  // ─────────────────────────────────────────────
  let buggyCount      = 0;
  let buggyExpected   = 0;
  let buggyPendingOps = 0;
  let buggyTotalClicks    = 0;
  let buggyTotalCollisions = 0;

  // Track what the count was when each op started,
  // so we can detect when two ops read the same value.
  let buggyLastReadValue = -1;

  function buggyLog(msg, type = '') {
    const log = document.getElementById('buggyLog');
    const entry = document.createElement('div');
    entry.className = 'log-entry ' + type;
    entry.textContent = `[${new Date().toLocaleTimeString('en',{hour12:false,hour:'2-digit',minute:'2-digit',second:'2-digit',fractionalSecondDigits:2})}] ${msg}`;
    log.appendChild(entry);
    log.scrollTop = log.scrollHeight;
    // keep log from growing forever
    while (log.children.length > 60) log.removeChild(log.firstChild);
  }

  function buggyRenderUI() {
    document.getElementById('buggyCount').textContent    = buggyCount;
    document.getElementById('buggyExpected').textContent = buggyExpected;
    const lost = buggyExpected - buggyCount;
    const diffEl = document.getElementById('buggyDiff');
    diffEl.textContent = lost;
    diffEl.className   = 'diff-value ' + (lost > 0 ? 'diff-negative' : 'diff-zero');
    document.getElementById('buggyPending').textContent    = buggyPendingOps;
    document.getElementById('buggyClicks').textContent     = buggyTotalClicks;
    document.getElementById('buggyLost').textContent       = lost;
    document.getElementById('buggyCollisions').textContent = buggyTotalCollisions;
  }

  function buggyIncrement() {
    buggyTotalClicks++;
    buggyExpected++;
    buggyPendingOps++;

    // ❌ THE BUG: we snapshot the count RIGHT NOW
    // before the async work completes.
    const snapshot = buggyCount;
    const myId = buggyTotalClicks;

    // Detect if another op already read this same value
    const isCollision = (snapshot === buggyLastReadValue && buggyPendingOps > 1);
    buggyLastReadValue = snapshot;

    buggyLog(`Op#${myId} READ  count=${snapshot}${isCollision ? ' ⚠️ STALE!' : ''}`,
             isCollision ? 'log-collision' : 'log-read');
    buggyRenderUI();

    // Simulate async work (variable delay to make race more visible)
    const delay = 150 + Math.random() * 250;

    setTimeout(() => {
      // ❌ We write snapshot+1 — but snapshot may be stale!
      const newValue = snapshot + 1;
      const wasStale = newValue <= buggyCount; // another op already wrote a higher value

      if (wasStale) {
        buggyTotalCollisions++;
        buggyLog(`Op#${myId} WRITE count=${newValue} ← COLLISION! (current=${buggyCount}, expected=${buggyExpected})`, 'log-collision');
        // Shake the display to show something went wrong
        const panel = document.getElementById('buggyPanel');
        panel.classList.remove('shake-anim');
        void panel.offsetWidth;
        panel.classList.add('shake-anim');
      } else {
        buggyLog(`Op#${myId} WRITE count=${newValue}`, 'log-write');
      }

      buggyCount = newValue; // overwrite with potentially stale value
      buggyPendingOps--;
      buggyRenderUI();
    }, delay);
  }

  function buggyReset() {
    buggyCount = buggyExpected = buggyPendingOps = 0;
    buggyTotalClicks = buggyTotalCollisions = 0;
    buggyLastReadValue = -1;
    document.getElementById('buggyLog').innerHTML = '';
    buggyRenderUI();
    buggyLog('--- Reset ---', 'log-ok');
  }


  // ─────────────────────────────────────────────
  // FIXED COUNTER STATE
  // ─────────────────────────────────────────────
  let fixedCount         = 0;
  let fixedExpected      = 0;
  let fixedTotalClicks   = 0;
  let fixedTotalProcessed = 0;
  let fixedQueue         = [];
  let fixedProcessing    = false;
  let fixedQueuedTotal   = 0;

  function fixedLog(msg, type = '') {
    const log = document.getElementById('fixedLog');
    const entry = document.createElement('div');
    entry.className = 'log-entry ' + type;
    entry.textContent = `[${new Date().toLocaleTimeString('en',{hour12:false,hour:'2-digit',minute:'2-digit',second:'2-digit',fractionalSecondDigits:2})}] ${msg}`;
    log.appendChild(entry);
    log.scrollTop = log.scrollHeight;
    while (log.children.length > 60) log.removeChild(log.firstChild);
  }

  function fixedRenderUI() {
    document.getElementById('fixedCount').textContent     = fixedCount;
    document.getElementById('fixedExpected').textContent  = fixedExpected;
    const lost = fixedExpected - fixedCount;
    const diffEl = document.getElementById('fixedDiff');
    diffEl.textContent = lost;
    diffEl.className   = 'diff-value ' + (lost > 0 ? 'diff-negative' : 'diff-zero');
    document.getElementById('fixedPending').textContent   = fixedQueue.length;
    document.getElementById('fixedClicks').textContent    = fixedTotalClicks;
    document.getElementById('fixedProcessed').textContent = fixedTotalProcessed;
    document.getElementById('fixedQueued').textContent    = fixedQueue.length;
  }

  // ✅ THE FIX: each click just pushes a job onto the queue.
  // The job is a function that receives the CURRENT count
  // at the time it executes, not at the time of the click.
  function fixedIncrement() {
    fixedTotalClicks++;
    fixedExpected++;
    fixedQueuedTotal++;

    const myId = fixedTotalClicks;
    fixedLog(`Op#${myId} QUEUED (queue size: ${fixedQueue.length + 1})`, 'log-queue');

    // Push a function — not a captured value!
    fixedQueue.push({ id: myId });
    fixedRenderUI();

    // Kick off the processor (safe to call multiple times)
    fixedProcessQueue();
  }

  // ✅ Serialized processor: only one item runs at a time.
  function fixedProcessQueue() {
    if (fixedProcessing) return; // already running, it will drain the queue
    fixedProcessing = true;
    fixedProcessNext();
  }

  function fixedProcessNext() {
    if (fixedQueue.length === 0) {
      fixedProcessing = false;
      fixedRenderUI();
      return;
    }

    const job = fixedQueue.shift();
    fixedRenderUI();

    // ✅ We READ the count here — at execution time, not click time.
    // By the time we get here, all previous ops have finished,
    // so fixedCount is always up-to-date.
    const readValue = fixedCount;
    fixedLog(`Op#${job.id} READ  count=${readValue} (fresh ✓)`, 'log-read');

    const delay = 150 + Math.random() * 250;

    setTimeout(() => {
      // ✅ Because reads are serialized, this is always correct.
      const newValue = readValue + 1;
      fixedCount = newValue;
      fixedTotalProcessed++;
      fixedLog(`Op#${job.id} WRITE count=${newValue} ✓`, 'log-ok');
      fixedRenderUI();

      // Process next item only after this one completes
      fixedProcessNext();
    }, delay);
  }

  function fixedReset() {
    fixedCount = fixedExpected = fixedTotalClicks = fixedTotalProcessed = 0;
    fixedQueuedTotal = 0;
    fixedQueue = [];
    fixedProcessing = false;
    document.getElementById('fixedLog').innerHTML = '';
    fixedRenderUI();
    fixedLog('--- Reset ---', 'log-ok');
  }

  // Initial render
  buggyRenderUI();
  fixedRenderUI();
  buggyLog('Ready — click Increment rapidly to trigger the bug!', 'log-ok');
  fixedLog('Ready — click Increment rapidly (queue keeps it correct)', 'log-ok');
</script>
</body>
