<div class="status-bar">
  <span>Spam delay: <strong>80–200ms async</strong> per op</span>
  <span>Ops in flight (buggy): <strong id="inflightBuggy">0</strong></span>
  <span>Ops in flight (fixed): <strong id="inflightFixed">0</strong></span>
  <span>Total clicks: <strong id="totalClicks">0</strong></span>
</div>

<div class="panels">

  <!-- ═══════════════════════════════════════════ BUGGY PANEL -->
  <div class="panel buggy">
    <div class="panel-title">🐛 Buggy — Race Condition</div>
    <div class="panel-desc">
