════════════════════════════════════════════════════ -->
<div class="explainer">
  <h2>📖 Why the bug happens — step by step</h2>

  <div class="timeline">
    <div class="tl-row">
      <div class="tl-head">Time</div>
      <div class="tl-head">🟠 Operation A</div>
      <div class="tl-head">🟣 Operation B (overlaps A)</div>
    </div>
    <div class="tl-row">
      <div class="tl-time">t = 0 ms</div>
      <div class="tl-a">READ  counter → 5</div>
      <div class="tl-b"></div>
    </div>
    <div class="tl-row">
      <div class="tl-time">t = 5 ms</div>
      <div class="tl-a"></div>
      <div class="tl-b">READ  counter → 5  ← <span class="highlight-bad">stale!</span></div>
    </div>
    <div class="tl-row">
      <div class="tl-time">t = 10 ms</div>
      <div class="tl-a">compute 5 + 1 = 6</div>
      <div class="tl-b">compute 5 + 1 = 6</div>
    </div>
    <div class="tl-row">
      <div class="tl-time">t = 15 ms</div>
      <div class="tl-a">WRITE counter ← 6</div>
      <div class="tl-b"></div>
    </div>
    <div class="tl-row">
      <div class="tl-time">t = 20 ms</div>
      <div class="tl-a"></div>
      <div class="tl-b">WRITE counter ← 6  ← <span class="highlight-bad">overwrites A!</span></div>
    </div>
    <div class="tl-row">
      <div class="tl-time">result</div>
      <div class="tl-a"><span class="highlight-bad">counter = 6, not 7 — one update lost</span></div>
      <div class="tl-b"></div>
    </div>
  </div>

  <p>
    <strong>The bug:</strong> Each async operation <em>reads</em> the counter at the moment it starts,
    <em>waits</em> a random delay (simulating a DB round-trip, fetch, etc.), then <em>writes</em>
    the value it computed back. If two operations overlap, the second one read a value that was already
    stale by the time it writes — silently discarding the first operation's work.
  </p>
  <p>
    <strong>The fix:</strong> Serialise writes through a promise-based queue. Each operation
    <em>awaits</em> the previous one before reading. The read always happens <em>after</em> the prior
    write commits, so no operation ever sees a stale value.
  </p>
</div>

<script>
// ─────────────────────────────────────────────────────────────────────────────
// Shared helpers
// ─────────────────────────────────────────────────────────────────────────────

function randomDelay(min = 30, max = 300) {
  return Math.floor(Math.random() * (max - min)) + min;
}

function appendLog(logEl, text, cls) {
  const entry = document.createElement('div');
  entry.className = `log-entry ${cls}`;
  entry.textContent = text;
  logEl.appendChild(entry);
  // keep last 120 entries
  while (logEl.children.length > 120) logEl.removeChild(logEl.firstChild);
  logEl.scrollTop = logEl.scrollHeight;
}

function ts() {
  return performance.now().toFixed(0).padStart(6, ' ') + 'ms';
}

// ─────────────────────────────────────────────────────────────────────────────
// BUGGY counter
// ─────────────────────────────────────────────────────────────────────────────
const buggy = {
  // The shared state — a plain object (pretend it's a remote DB row)
  state: { counter: 0 },

  expectedValue: 0,
  conflictCount:  0,
  clickCount:     0,
  inflightOps:    [],   // array of { id, readValue, delay }
  opIdCounter:    0,

  els: {
    val:           document.getElementById('buggy-val'),
    expected:      document.getElementById('buggy-expected'),
    lost:          document.getElementById('buggy-lost'),
    log:           document.getElementById('buggy-log'),
    inflightVis:   document.getElementById('buggy-inflight-vis'),
    inflightCount: document.getElementById('buggy-inflight-count'),
    conflicts:     document.getElementById('buggy-conflicts'),
    clicks:        document.getElementById('buggy-clicks'),
  },

  reset() {
    this.state.counter  = 0;
    this.expectedValue  = 0;
    this.conflictCount  = 0;
    this.clickCount     = 0;
    this.inflightOps    = [];
    this.opIdCounter    = 0;
    this.render();
    this.els.log.innerHTML = '';
    appendLog(this.els.log, '— reset —', 'info');
  },

  render() {
    const actual   = this.state.counter;
    const expected = this.expectedValue;
    const lost     = expected - actual;

    this.els.val.textContent      = actual;
    this.els.expected.textContent = expected;
    this.els.lost.textContent     = lost;
    this.els.conflicts.textContent = this.conflictCount;
    this.els.clicks.textContent    = this.clickCount;
    this.els.inflightCount.textContent = this.inflightOps.length;

    this.els.val.className = 'counter-value ' +
      (lost > 0 ? 'wrong' : actual > 0 ? 'right' : 'neutral');

    // inflight pills
    const vis = this.els.inflightVis;
    vis.innerHTML = '';
    if (this.inflightOps.length === 0) {
      vis.innerHTML = '<span class="inflight-label">None</span>';
    } else {
      this.inflightOps.forEach(op => {
        const pill = document.createElement('span');
        pill.className = `op-pill ${op.phase}`;
        pill.textContent = `#${op.id} read=${op.readValue} d=${op.delay}ms`;
        vis.appendChild(pill);
      });
    }
  },

  // ── THE BUGGY INCREMENT ──────────────────────────────────────────────────
  // Classic read-modify-write with a delay between read and write.
  // Multiple overlapping calls read the SAME stale value.
  increment() {
    this.clickCount++;
    this.expectedValue++;

    const id    = ++this.opIdCounter;
    const delay = randomDelay();

    // ❶ READ — capture current value RIGHT NOW
    const readValue = this.state.counter;

    const opEntry = { id, readValue, delay, phase: 'pending' };
    this.inflightOps.push(opEntry);
    this.render();

    appendLog(this.els.log,
      `[${ts()}] #${id} READ  counter=${readValue}  (delay=${delay}ms)`,
      'read');

    // ❷ WAIT — simulate async work (network, DB, computation)
    setTimeout(() => {
      const newValue = readValue + 1;

      // ❸ WRITE — write back the value we computed from a potentially stale read
      const before = this.state.counter;
      this.state.counter = newValue;

      opEntry.phase = 'writing';

      const isConflict = before !== readValue;
      if (isConflict) {
        this.conflictCount++;
        appendLog(this.els.log,
          `[${ts()}] #${id} WRITE ${readValue}+1=${newValue}  ` +
          `⚠ CONFLICT! counter was ${before}, expected ${readValue} — LOST UPDATE`,
          'conflict');
      } else {
        appendLog(this.els.log,
          `[${ts()}] #${id} WRITE ${readValue}+1=${newValue}  ✓`,
          'write');
      }

      // remove from inflight
      this.inflightOps = this.inflightOps.filter(o => o.id !== id);
      this.render();
    }, delay);
  }
};

// ─────────────────────────────────────────────────────────────────────────────
// FIXED counter — promise queue serialises all operations
// ─────────────────────────────────────────────────────────────────────────────
const fixed = {
  state: { counter: 0 },

  expectedValue: 0,
  conflictCount:  0,   // should stay 0 forever
  clickCount:     0,
  queuedOps:      [],
  opIdCounter:    0,

  // The queue tail — each new operation chains onto this promise
  _queue: Promise.resolve(),

  els: {
    val:           document.getElementById('fixed-val'),
    expected:      document.getElementById('fixed-expected'),
    lost:          document.getElementById('fixed-lost'),
    log:           document.getElementById('fixed-log'),
    inflightVis:   document.getElementById('fixed-inflight-vis'),
    inflightCount: document.getElementById('fixed-inflight-count'),
    conflicts:     document.getElementById('fixed-conflicts'),
    clicks:        document.getElementById('fixed-clicks'),
  },

  reset() {
    this.state.counter  = 0;
    this.expectedValue  = 0;
    this.conflictCount  = 0;
    this.clickCount     = 0;
    this.queuedOps      = [];
    this.opIdCounter    = 0;
    this._queue         = Promise.resolve();
    this.render();
    this.els.log.innerHTML = '';
    appendLog(this.els.log, '— reset —', 'info');
  },

  render() {
    const actual   = this.state.counter;
    const expected = this.expectedValue;
    const lost     = expected - actual;

    this.els.val.textContent      = actual;
    this.els.expected.textContent = expected;
    this.els.lost.textContent     = lost;
    this.els.conflicts.textContent = this.conflictCount;
    this.els.clicks.textContent    = this.clickCount;
    this.els.inflightCount.textContent = this.queuedOps.length;

    this.els.val.className = 'counter-value ' +
      (lost > 0 ? 'wrong' : actual > 0 ? 'right' : 'neutral');

    const vis = this.els.inflightVis;
    vis.innerHTML = '';
    if (this.queuedOps.length === 0) {
      vis.innerHTML = '<span class="inflight-label">Empty</span>';
    } else {
      this.queuedOps.forEach((op, i) => {
        const pill = document.createElement('span');
        pill.className = `op-pill ${i === 0 ? 'writing' : 'pending'}`;
        pill.textContent = `#${op.id}${i === 0 ? ' ▶' : ''}`;
        vis.appendChild(pill);
      });
    }
  },

  // ── THE FIXED INCREMENT ──────────────────────────────────────────────────
  // Every increment is chained onto the queue tail.
  // The READ happens INSIDE the awaited chain, so it always sees the
  // value committed by the previous operation — never a stale snapshot.
  increment() {
    this.clickCount++;
    this.expectedValue++;

    const id    = ++this.opIdCounter;
    const delay = randomDelay();

    const opEntry = { id, delay };
    this.queuedOps.push(opEntry);
    this.render();

    appendLog(this.els.log,
      `[${ts()}] #${id} QUEUED (delay=${delay}ms, queue depth=${this.queuedOps.length})`,
      'info');

    // Chain onto the queue — this operation will not start until all
    // previously queued operations have fully completed.
    this._queue = this._queue.then(() => {
      return new Promise(resolve => {

        // ❶ READ — happens HERE, after all prior ops have committed
        const readValue = this.state.counter;

        appendLog(this.els.log,
          `[${ts()}] #${id} READ  counter=${readValue}  (delay=${delay}ms)`,
          'read');

        // ❷ WAIT — same async delay as the buggy version
        setTimeout(() => {
          const newValue = readValue + 1;

          // ❸ WRITE — no conflict possible because we own the queue
          this.state.counter = newValue;

          appendLog(this.els.log,
            `[${ts()}] #${id} WRITE ${readValue}+1=${newValue}  ✓`,
            'ok');

          this.queuedOps = this.queuedOps.filter(o => o.id !== id);
          this.render();
          resolve();
        }, delay);
      });
    });
  }
};

// ─────────────────────────────────────────────────────────────────────────────
// Wire up buttons
// ─────────────────────────────────────────────────────────────────────────────

document.getElementById('btn-buggy-inc').addEventListener('click', () => buggy.increment());
document.getElementById('btn-fixed-inc').addEventListener('click', () => fixed.increment());

document.getElementById('btn-buggy-blast').addEventListener('click', () => {
  for (let i = 0; i < 10; i++) {
    // stagger by 0–40ms so they actually overlap
    setTimeout(() => buggy.increment(), Math.random() * 40);
  }
});

document.getElementById('btn-fixed-blast').addEventListener('click', () => {
  for (let i = 0; i < 10; i++) {
    setTimeout(() => fixed.increment(), Math.random() * 40);
  }
});

document.getElementById('btn-buggy-reset').addEventListener('click', () => buggy.reset());
document.getElementById('btn-fixed-reset').addEventListener('click', () => fixed.reset());

// initial render
buggy.render();
fixed.render();
</script>
</body>
</html>
```

## What this actually shows you

**The bug is real and visible** — hit "💥 Blast ×10" on the buggy side and watch the counter land on something like 3 instead of 10. The "Lost updates" counter tells you exactly how many writes were silently discarded.

### Why it works as a demo

| What you see | What it proves |
|---|---|
| Multiple in-flight pills appearing simultaneously on the buggy side | Two ops read the same stale value before either writes |
| `⚠ CONFLICT! counter was 4, expected 2` in the log | The write-back overwrote a newer value with a stale computation |
| Fixed side always lands on exactly the right number | Queue serialisation prevents any two ops from overlapping |
| Fixed side "Conflicts" counter stays permanently at 0 | Not just lucky timing — structurally impossible to conflict |

### The core mechanism

- **Buggy**: `READ` happens immediately on click → random delay → `WRITE` using the captured (now stale) value. Two clicks 5ms apart both read `5`, both compute `6`, counter ends at `6` not `7`.
- **Fixed**: The `READ` is *inside* `this._queue.then(...)` — it only executes after the previous promise resolves. The delay is identical, but the read is always fresh because it happens after the prior commit.

