            diffEl.className = 'diff-count good';
          }
        }
      }
    }, delay);
  }

  function buggySpam() {
    const before = buggyCounter;
    const expected = before + 10;
    setDisplay('buggy-expected', expected);
    document.getElementById('buggy-diff').textContent = '';
    log('buggy-log', `── spam start (counter=${before}, expect ${expected}) ──`, 'log-info');
    for (let i = 1; i <= 10; i++) {
      buggyIncrement(true, i, expected);
    }
  }

  function buggyReset() {
    buggyCounter = 0;
    setDisplay('buggy-counter', 0);
    setDisplay('buggy-expected', '—');
    document.getElementById('buggy-log').innerHTML = '';
    document.getElementById('buggy-diff').textContent = '';
  }

  // ─── FIXED implementation ──────────────────────────────────────
  // THE FIX: no local snapshot. The read and write both happen
  // inside the callback, which runs atomically on the event loop.
  // Each callback sees the latest committed value of fixedCounter.

  function fixedIncrement(isSpam, spamId, expectedAfter) {
    const delay = Math.floor(Math.random() * 80) + 10;

    if (isSpam) {
