        log('fixed-log',
          `[done  #${spamId}] counter=${fixedCounter}`,
          'log-ok');

        if (spamId === 10 || fixedCounter === expectedAfter) {
          // wait a tiny bit for all callbacks to finish before reporting
        }
      }
    }, delay);
  }

  // We need to detect when all 10 fixed callbacks have fired.
  // Use a simple completion counter per spam batch.
  function fixedSpam() {
    const before = fixedCounter;
    const expected = before + 10;
    setDisplay('fixed-expected', expected);
    document.getElementById('fixed-diff').textContent = '';
    log('fixed-log', `── spam start (counter=${before}, expect ${expected}) ──`, 'log-info');

    let completed = 0;
